import type { Project, SortOption, GalleryQuery } from './types'

const DATA_PATH = new URL('./data/projects.json', import.meta.url).pathname

const readProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  return file.json()
}

const writeProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

const sortProjects = (projects: Project[], sort: SortOption): Project[] => {
  const sorted = [...projects]
  switch (sort) {
    case 'date-desc':
      return sorted.sort((a, b) => b.dateAdded.localeCompare(a.dateAdded))
    case 'date-asc':
      return sorted.sort((a, b) => a.dateAdded.localeCompare(b.dateAdded))
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
    default:
      return sorted
  }
}

export const getAllTags = async (): Promise<string[]> => {
  const projects = await readProjects()
  const tagSet = new Set<string>()
  for (const project of projects) {
    for (const tag of project.tags) {
      tagSet.add(tag)
    }
  }
  return [...tagSet].sort()
}

export const queryProjects = async (query: GalleryQuery): Promise<Project[]> => {
  let projects = await readProjects()

  if (query.tag) {
    const tag = query.tag.toLowerCase()
    projects = projects.filter((p) =>
      p.tags.some((t) => t.toLowerCase() === tag)
    )
  }

  if (query.q) {
    const search = query.q.toLowerCase()
    projects = projects.filter((p) =>
      p.title.toLowerCase().includes(search)
    )
  }

  const sort = query.sort ?? 'date-desc'
  return sortProjects(projects, sort)
}

export const getProject = async (id: string): Promise<Project | undefined> => {
  const projects = await readProjects()
  return projects.find((p) => p.id === id)
}

export const addProject = async (project: Project): Promise<Project> => {
  const projects = await readProjects()
  const existing = projects.findIndex((p) => p.id === project.id)
  if (existing !== -1) {
    throw new Error(`Project with id "${project.id}" already exists`)
  }
  projects.push(project)
  await writeProjects(projects)
  return project
}

export const updateProject = async (id: string, updates: Partial<Project>): Promise<Project> => {
  const projects = await readProjects()
  const index = projects.findIndex((p) => p.id === id)
  if (index === -1) {
    throw new Error(`Project with id "${id}" not found`)
  }
  projects[index] = { ...projects[index], ...updates, id }
  await writeProjects(projects)
  return projects[index]
}

export const deleteProject = async (id: string): Promise<void> => {
  const projects = await readProjects()
  const index = projects.findIndex((p) => p.id === id)
  if (index === -1) {
    throw new Error(`Project with id "${id}" not found`)
  }
  projects.splice(index, 1)
  await writeProjects(projects)
}

