const s = toStyleString

const renderTag = (tag: string, activeTag?: string) => {
  const isActive = activeTag?.toLowerCase() === tag.toLowerCase()
  const style = isActive ? controlStyles.tagActive : controlStyles.tag
  const href = isActive ? '/' : `/?tag=${encodeURIComponent(tag)}`
  return h('a', { href, style: s(style) }, tag)
}

