const renderLightboxScript = (images: string[]) => `
  (function() {
    var images = ${JSON.stringify(images)};
    var idx = 0;
    var overlay = document.getElementById('lightbox');
    var img = document.getElementById('lightbox-img');
    var counter = document.getElementById('lightbox-counter');
    function show(i) { idx = i; img.src = images[idx]; counter.textContent = (idx+1)+' / '+images.length; overlay.style.display = 'flex'; }
    function hide() { overlay.style.display = 'none'; }
    function prev() { show((idx - 1 + images.length) % images.length); }
    function next() { show((idx + 1) % images.length); }
    document.querySelectorAll('[data-lightbox]').forEach(function(el, i) { el.onclick = function() { show(i); }; });
    document.getElementById('lb-close').onclick = hide;
    document.getElementById('lb-prev').onclick = prev;
    document.getElementById('lb-next').onclick = next;
    overlay.onclick = function(e) { if (e.target === overlay) hide(); };
    document.addEventListener('keydown', function(e) {
      if (overlay.style.display !== 'flex') return;
      if (e.key === 'Escape') hide();
      if (e.key === 'ArrowLeft') prev();
      if (e.key === 'ArrowRight') next();
    });
  })();
`

