import type { GalleryQuery, SortOption, Project } from './types'
import { queryProjects, getProject, getAllTags, addProject, updateProject, deleteProject } from './data'
import { renderGalleryPage, renderDetailPage, renderNotFound } from './render'

const VALID_SORTS: SortOption[] = ['date-desc', 'date-asc', 'alpha-asc', 'alpha-desc']

const parseQuery = (url: URL): GalleryQuery => {
  const tag = url.searchParams.get('tag') ?? undefined
  const q = url.searchParams.get('q') ?? undefined
  const sortParam = url.searchParams.get('sort')
  const sort = VALID_SORTS.includes(sortParam as SortOption)
    ? (sortParam as SortOption)
    : 'date-desc'
  return { tag, q, sort }
}

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string, status = 200) =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const handleGallery = async (url: URL): Promise<Response> => {
  const query = parseQuery(url)
  const [projects, allTags] = await Promise.all([
    queryProjects(query),
    getAllTags(),
  ])
  const html = renderGalleryPage(projects, allTags, query)
  return htmlResponse(html)
}

const handleDetail = async (id: string): Promise<Response> => {
  const project = await getProject(id)
  if (!project) {
    return htmlResponse(renderNotFound(), 404)
  }
  return htmlResponse(renderDetailPage(project))
}

const handleAddProject = async (req: Request): Promise<Response> => {
  const body = (await req.json()) as Project
  if (!body.id || !body.title) {
    return jsonResponse({ error: 'id and title are required' }, 400)
  }
  const project = await addProject({
    id: body.id,
    title: body.title,
    description: body.description ?? '',
    fullDescription: body.fullDescription ?? '',
    thumbnail: body.thumbnail ?? '',
    images: body.images ?? [],
    tags: body.tags ?? [],
    demoUrl: body.demoUrl ?? '',
    sourceUrl: body.sourceUrl ?? '',
    dateAdded: body.dateAdded ?? new Date().toISOString().slice(0, 10),
  })
  return jsonResponse(project, 201)
}

const handleUpdateProject = async (req: Request, id: string): Promise<Response> => {
  const updates = (await req.json()) as Partial<Project>
  const project = await updateProject(id, updates)
  return jsonResponse(project)
}

const handleDeleteProject = async (id: string): Promise<Response> => {
  await deleteProject(id)
  return jsonResponse({ deleted: id })
}

const router = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { method } = req
  const path = url.pathname

  // Gallery page
  if (path === '/' && method === 'GET') {
    return handleGallery(url)
  }

  // Detail page
  const detailMatch = path.match(/^\/project\/([a-z0-9-]+)$/)
  if (detailMatch && method === 'GET') {
    return handleDetail(detailMatch[1])
  }

  // API: add project
  if (path === '/projects' && method === 'POST') {
    return handleAddProject(req)
  }

  // API: update / delete project
  const apiMatch = path.match(/^\/projects\/([a-z0-9-]+)$/)
  if (apiMatch && method === 'PUT') {
    return handleUpdateProject(req, apiMatch[1])
  }
  if (apiMatch && method === 'DELETE') {
    return handleDeleteProject(apiMatch[1])
  }

  return htmlResponse(renderNotFound(), 404)
}

export default {
  port: 3000,
  fetch: router,
}
